class Solution:
    def sumFourDivisors(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        def count_divisors(n):
            divisors = []
            i = 1
            while i * i <= n:
                if n % i == 0:
                    divisors.append(i)
                    if i != n // i:
                        divisors.append(n // i)
                i += 1
            return divisors

        total = 0
        for num in nums:
            divisors = count_divisors(num)
            if len(divisors) == 4:
                total += sum(divisors)

        return total
